\begin{parts}
\part Here are the ingredients needed to make a pasta bake to serve 12 people.

\begin{center}
\begin{tabular}{|l|}
\hline
250\,g butter \\
600\,g pasta \\
460\,g mushrooms \\
280\,g cheese \\
800\,ml milk \\
\hline
\end{tabular}
\end{center}

\begin{subparts}
\subpart Find the mass of the cheese as a percentage of the mass of the mushrooms.

\AnswerLine[][\%]
\Marks{1}

\subpart Find the mass of butter needed to make a pasta bake to serve 18 people.

\AnswerLine[][g]
\Marks{2}

\subpart Monica has 2.2 litres of milk and 1.5\,kg of each other ingredient.

Calculate the greatest number of people she can serve with pasta bake.

\AnswerLine[][]
\Marks{3}

\end{subparts}

\part In 2019, a packet of pasta cost \$2.40.

This was an increase of 25\% of the cost of a packet in 2018.

\begin{subparts}
\subpart Work out the cost in 2018.

\AnswerLine[\$][]
\Marks{2}

\subpart In 2020, the cost of a packet increased by 15\% from the cost in 2019.

Work out the total percentage increase in the cost of a packet from 2018 to 2020.

\AnswerLine[][\%]
\Marks{3}

\end{subparts}

